 30	const PolicyEnactmentsDrawer: FC<PolicyEnactmentsDrawerProps> = ({
 31	  selectedPolicy,
 32	  selectedState,
 33	  onClose,
 34	  enactments,
 35	}) => {
 36	  const { t } = useNMStateTranslation();
 37	
 38	  const {
 39	    available: availableEnactments,
 40	    pending: pendingEnactments,
 41	    progressing: progressingEnactments,
 42	    failing: failingEnactments,
 43	    aborted: abortedEnactments,
 44	  } = categorizeEnactments(enactments);
 45	
 46	  const tabsData = useMemo(
 47	    () => [
 48	      {
 49	        title: EnactmentStatuses.Failing,
 50	        icon: <RedExclamationCircleIcon />,
 51	        enactments: failingEnactments,
 52	      },
 53	      {
 54	        title: EnactmentStatuses.Aborted,
 55	        icon: <CloseIcon color={dangerColor.value} />,
 56	        enactments: abortedEnactments,
 57	      },
 58	      {
 59	        title: EnactmentStatuses.Available,
 60	        icon: <CheckIcon color={successColor.value} />,
 61	        enactments: availableEnactments,
 62	      },
 63	      {
 64	        title: EnactmentStatuses.Progressing,
 65	        icon: <InProgressIcon />,
 66	        enactments: progressingEnactments,
 67	      },
 68	      {
 69	        title: EnactmentStatuses.Pending,
 70	        icon: <HourglassHalfIcon />,
 71	        enactments: pendingEnactments,
 72	      },
 73	    ],
 74	    [enactments],
 75	  );
 76	
 77	  const [selectedTab, setSelectedTab] = useState<string | number>(0);
 78	
 79	  useEffect(() => {
 80	    setSelectedTab(tabsData.findIndex((tab) => tab.title === selectedState));
 81	  }, [selectedPolicy, selectedState]);
 82	
 83	  return (
 84	    <Modal
 85	      aria-label="Policy enactments drawer"
 86	      className="ocs-modal co-catalog-page__overlay co-catalog-page__overlay--right policy-enactments-drawer"
 87	      isOpen={!!selectedPolicy}
 88	      onClose={onClose}
 89	      disableFocusTrap
 90	      header={<h2>{t('Matched nodes summary')}</h2>}
 91	    >
 92	      <div className="modal-body modal-body-border modal-body-content">
 93	        <Tabs
 94	          activeKey={selectedTab}
 95	          onSelect={(event, key) => setSelectedTab(key)}
 96	          isBox
 97	          aria-label={t('Enactments categorized by status')}
 98	          role="region"
 99	        >
100	          {tabsData.map((tabData, index) => (
101	            <Tab
102	              eventKey={index}
103	              key={tabData.title}
104	              isDisabled={tabData.enactments.length === 0}
105	              aria-label={t('Display all {{status}} enactments', { status: tabData.title })}
106	              title={
107	                <>
108	                  <TabTitleIcon>{tabData.icon}</TabTitleIcon>
109	                  <TabTitleText> {t(tabData.title)} </TabTitleText>
110	                </>
111	              }
112	            >
113	              {tabData?.enactments?.map((enhactment) => (
114	                <ExpandableSection
115	                  toggleText={enhactment?.metadata?.name}
116	                  key={enhactment?.metadata?.name}
117	                >
118	                  <pre className="policy-enactments-drawer__tabs__expandable-content">
119	                    {findConditionType(enhactment?.status?.conditions, tabData.title)?.message}
120	                  </pre>
121	                </ExpandableSection>
122	              ))}
123	            </Tab>
124	          ))}
125	        </Tabs>
126	      </div>
127	    </Modal>
128	  );
129	};
130	
131	export default PolicyEnactmentsDrawer;

